#include <vector>
#include <string>
#include <unordered_set>

// Function to generate a complex pattern using a sequence of numbers
// *highlighted section* This function uses nested loops and mathematical operations to fabricate a complex pattern
void generateComplexPattern(int size) {
    std::vector<std::string> pattern;
    std::unordered_set<std::string> uniqueElements;

    for (int i = 0; i < size; ++i) {
        std::string row;
        for (int j = 0; j < size; ++j) {
            int value = (i * j) % 10 + 1;
            row += std::to_string(value) + " ";
            uniqueElements.insert(std::to_string(value));
        }
        pattern.push_back(row);
    }

    // *highlighted section* Display the generated pattern
    for (const auto& line : pattern) {
        std::cout << line << std::endl;
    }

    // *highlighted section* Output the count of unique elements in the pattern
    std::cout << "Number of unique elements: " << uniqueElements.size() << std::endl;
}

